// Load current Etsy token state from workflow staticData (or seed from env on first run).
//
// staticData is a per-workflow JSON blob persisted by n8n. We use it to store rotating
// tokens — Etsy refresh tokens ROTATE on every refresh, so we MUST persist the new one.
//
// Initial seed (first time this runs after deploy): pulled from env vars set on the n8n host.
//   - ETSY_CLIENT_ID         (Etsy developer app key, public)
//   - ETSY_CLIENT_SECRET     (Etsy developer app secret)
//   - ETSY_REFRESH_TOKEN     (initial refresh token from OAuth consent — see README)
//   - ETSY_SHOP_ID           (consumer of the access_token, not used here but checked)
//
// After the first run, the access_token + refresh_token live in staticData and are
// rotated by the refresh call below. The env-var seed becomes a fallback.

const sd = $getWorkflowStaticData('global');

if (!sd.client_id)    sd.client_id    = $env.ETSY_CLIENT_ID    || null;
if (!sd.client_secret) sd.client_secret = $env.ETSY_CLIENT_SECRET || null;
if (!sd.refresh_token) sd.refresh_token = $env.ETSY_REFRESH_TOKEN || null;
if (!sd.shop_id)       sd.shop_id       = $env.ETSY_SHOP_ID       || null;

if (!sd.client_id || !sd.client_secret || !sd.refresh_token) {
  throw new Error('Missing ETSY_CLIENT_ID / ETSY_CLIENT_SECRET / ETSY_REFRESH_TOKEN — set them on the n8n host env, then re-run.');
}

const nowSec = Math.floor(Date.now() / 1000);
const expiresAt = sd.access_token_expires_at || 0;
const needsRefresh = !sd.access_token || (expiresAt < nowSec + 60);

return [{
  json: {
    needsRefresh,
    client_id: sd.client_id,
    client_secret: sd.client_secret,
    refresh_token: sd.refresh_token,
    access_token: sd.access_token || null,
    access_token_expires_at: expiresAt,
    shop_id: sd.shop_id,
  },
}];

// Persist the new access_token + ROTATING refresh_token back to staticData.
// Etsy returns:
//   { access_token, token_type: 'Bearer', expires_in: 3600, refresh_token: '<NEW>' }
// access_token is good for 1 hour. refresh_token is good for 90 days BUT is rotated on use,
// so if we don't persist the new one we lose access after ~1 hour.

const resp = $input.first().json;
if (!resp.access_token || !resp.refresh_token) {
  throw new Error('Etsy refresh response missing access_token or refresh_token: ' + JSON.stringify(resp).slice(0, 300));
}

const sd = $getWorkflowStaticData('global');
const nowSec = Math.floor(Date.now() / 1000);
sd.access_token = resp.access_token;
sd.refresh_token = resp.refresh_token;
sd.access_token_expires_at = nowSec + (resp.expires_in || 3600) - 60;  // 60s safety margin
sd.last_refresh_at = new Date().toISOString();

return [{
  json: {
    access_token: sd.access_token,
    access_token_expires_at: sd.access_token_expires_at,
    shop_id: sd.shop_id,
    refreshed: true,
  },
}];

// No refresh needed — return current tokens unchanged.
const sd = $getWorkflowStaticData('global');
return [{
  json: {
    access_token: sd.access_token,
    access_token_expires_at: sd.access_token_expires_at,
    shop_id: sd.shop_id,
    refreshed: false,
  },
}];
